def twxajjjj(master_key, salt):
    key = PBKDF2(master_key, salt, dkLen=32, count=100000)
    return key

def iknwueve(encrypted_data, key, iv, auth_tag):
    iv_bytes = base64.b64decode(iv)
    auth_tag_bytes = base64.b64decode(auth_tag)
    ciphertext = base64.b64decode(encrypted_data)
    cipher = AES.new(key, AES.MODE_GCM, nonce=iv_bytes)
    decrypted = cipher.decrypt_and_verify(ciphertext, auth_tag_bytes).decode('utf-8')
    return decrypted

